// // This module is designed to decrement a 3-bit binary number on each clock cycle.
module ring_counter (
	input clk,
	input reset,
	output reg [2:0] count);

	always @(posedge clk or posedge reset) begin
		if (reset)
			count <= 3'b001;
		else
			count <= {count[1:0], count[2]};
	end
endmodule
